scwin.f_DivAllAmt = function () {
  let row = ds_cntrBulkOutIntendDetail.getRowCount();
  if (row == 0) return;
  let jdgAmt = Number(ed_input24.getValue());
  let cstmdtAmt = Number(ed_input25.getValue());
  let totWt = Number(ds_cntrBulkOutIntend.getCellData(0, "totWt"));
  let totCbm = Number(ds_cntrBulkOutIntend.getCellData(0, "totCbm"));
  let sumCbm = 0,
    sumWt = 0,
    sumCstmdtAmt = 0,
    sumJdgAmt = 0;
  for (let i = 0; i < row; i++) {
    ds_cntrBulkOutIntendDetail.setCellData(i, "jdgAmt", Math.round(jdgAmt / row));
    sumJdgAmt += Number(ds_cntrBulkOutIntendDetail.getCellData(i, "jdgAmt"));
    ds_cntrBulkOutIntendDetail.setCellData(i, "cstmdtAmt", Math.round(cstmdtAmt / row));
    sumCstmdtAmt += Number(ds_cntrBulkOutIntendDetail.getCellData(i, "cstmdtAmt"));
    ds_cntrBulkOutIntendDetail.setCellData(i, "wt", Math.round(totWt / row) * 1000 / 1000);
    sumWt += Number(ds_cntrBulkOutIntendDetail.getCellData(i, "wt"));
    ds_cntrBulkOutIntendDetail.setCellData(i, "cbm", Math.round(totCbm / row) * 1000 / 1000);
    sumCbm += Number(ds_cntrBulkOutIntendDetail.getCellData(i, "cbm"));
    if (i == row - 1) {
      if (sumJdgAmt != jdgAmt) {
        ds_cntrBulkOutIntendDetail.setCellData(i, "jdgAmt", Number(ds_cntrBulkOutIntendDetail.getCellData(i, "jdgAmt")) + (jdgAmt - sumJdgAmt));
      }
      if (sumCstmdtAmt != cstmdtAmt) {
        ds_cntrBulkOutIntendDetail.setCellData(i, "cstmdtAmt", Number(ds_cntrBulkOutIntendDetail.getCellData(i, "cstmdtAmt")) + (cstmdtAmt - sumCstmdtAmt));
      }
      if (sumWt != totWt) {
        ds_cntrBulkOutIntendDetail.setCellData(i, "wt", Number(ds_cntrBulkOutIntendDetail.getCellData(i, "wt")) + (totWt - sumWt));
      }
      if (sumCbm != totCbm) {
        ds_cntrBulkOutIntendDetail.setCellData(i, "cbm", Number(ds_cntrBulkOutIntendDetail.getCellData(i, "cbm")) + (totCbm - sumCbm));
      }
    }
  }
};
